$bytes = [System.Convert]::FromBase64String(($b64 -replace "\s",""))
$path = ".\netlify\functions\ghl-webhook.js"
[System.IO.File]::WriteAllBytes((Resolve-Path ".").Path + "\netlify\functions\ghl-webhook.js", $bytes)
Write-Host "Wrote ghl-webhook.js"
Write-Host "  event routing present:" (Select-String -Path $path -Pattern "call_booked" -SimpleMatch -Quiet)
Write-Host "  booking sequence present:" (Select-String -Path $path -Pattern "booking_state" -SimpleMatch -Quiet)
Write-Host "  abandon nudge present:" (Select-String -Path $path -Pattern "sendAbandonNudge" -SimpleMatch -Quiet)
